B.Rq=new A.V(B.ae,"Tense signals when an action happens","In aviation English, choosing the right tense is critical. ATC uses **present simple** for permanent facts, **present continuous** for current actions, and **past simple** for completed events in reports.\n\nMixing tenses in checklists or reports is a common exam error.",null,null,null)
B.Mk=new A.oS(4,"tensesTimeline")
B.Rr=new A.V(B.eY,"Tenses on a timeline",null,null,B.Mk,null)
B.Qu=new A.V(B.B,"Simple vs. Continuous",'**Present Simple** \u2014 facts, routines, permanent states\n\u2192 "The ILS localizer **operates** on frequencies 108\u2013111.95 MHz."\n\n**Present Continuous** \u2014 actions happening now, temporary\n\u2192 "The aircraft **is climbing** through flight level 180."\n\n**Past Simple** \u2014 completed events (reports, logs)\n\u2192 "The crew **performed** the before-start checklist at 0612Z."\n\n**Past Continuous** \u2014 ongoing past action interrupted\n\u2192 "The aircraft **was taxiing** when the bird strike **occurred**."',null,null,null)
B.L7=new A.aH("The aircraft is currently holding at ELVIN fix due to traffic congestion.","U\xe7ak, trafik yo\u011funlu\u011fu nedeniyle \u015fu anda ELVIN noktas\u0131nda bekleme yap\u0131yor.","is currently holding")
B.Lz=new A.aH("The crew completed the after-landing checklist at 14:32 UTC.","Ekip ini\u015f sonras\u0131 kontrol listesini 14:32 UTC'de tamamlad\u0131.","completed")
B.Ld=new A.aH("ATIS information Bravo states that the active runway is 36L.","ATIS bilgisi Bravo, aktif pistin 36L oldu\u011funu belirtiyor.","states")
