B.R8=new A.V(B.ae,"The airport environment has precise terminology","Ground operations vocabulary is tested heavily in fill-in-the-blank and reading comprehension questions. Knowing the difference between a **taxiway**, **runway**, **apron**, and **ramp** is essential for safe operations and exam success.",null,null,null)
B.PS=new A.V(B.B,"\ud83d\udeec Airport Movement Areas","**Runway** \u2014 paved surface for takeoff and landing\n**Taxiway** \u2014 paved path connecting runways to aprons (named A, B, C\u2026)\n**Apron (Ramp)** \u2014 area for parking, loading, servicing aircraft\n**Holding Bay** \u2014 area where aircraft wait before entering runway\n**Threshold** \u2014 beginning of the runway available for landing\n**Displaced Threshold** \u2014 landing threshold moved from physical runway end\n**Stopway** \u2014 paved area beyond runway end, usable for stopping only",null,null,null)
B.QZ=new A.V(B.B,"\ud83d\udea7 Ground Movement Terms","**Pushback** \u2014 towing aircraft backward from gate using a tug\n**Tow** \u2014 moving aircraft with a ground vehicle\n**Ground power unit (GPU)** \u2014 provides external electrical power\n**Chocks** \u2014 wheel blocks preventing movement\n**Jet bridge / Jetway** \u2014 passenger boarding bridge\n**FOD** \u2014 Foreign Object Debris (anything on runway/taxiway that could damage aircraft)\n**Ground stop** \u2014 ATC directive halting departures",null,null,null)
B.LC=new A.aH("Hold short of taxiway Charlie, there is an aircraft being towed across.","Charlie taksi yolunun \xf6n\xfcnde bekleyin, bir u\xe7ak \xe7ekiliyor.","being towed")
B.LH=new A.aH("FOD inspection of the runway must be completed before the first departure.","\u0130lk kalk\u0131\u015ftan \xf6nce pistin yabanc\u0131 cisim denetimi tamamlanmal\u0131d\u0131r.","FOD inspection")
B.KU=new A.aH("The aircraft requires GPU connection as the APU is unserviceable.","APU ar\u0131zal\u0131 oldu\u011fundan u\xe7ak yer g\xfc\xe7 \xfcnitesi ba\u011flant\u0131s\u0131 gerektiriyor.","GPU connection")
B.T1=s([B.LC,B.LH,B.KU],t.l)
B.Rp=new A.V(B.af,"Ground Operations in Context",null,B.T1,null,null)
B.Qy=new A.V(B.ag,"\u2708\ufe0f Exam Tip","Common confusion pairs:\n\u2022 **Apron** = parking/service area | **Tarmac** = informal term for apron/taxiway (avoid in formal use)\n\u2022 **Taxiway** = movement path | **Runway** = takeoff/landing only\n\u2022 **Gate** = passenger boarding position | **Stand/Bay** = parking position (no gate)\n\u2022 **Pushback** = aircraft moves backward | **Tow** = any direction with a vehicle",null,null,null)
B.Wf=s(["Taxiway","Runway","Apron","Threshold"],t.s)
