B.S7=new A.V(B.ae,"Safety equipment names must be exact","Using incorrect names for safety equipment can cause dangerous misunderstandings. Exam questions test precise knowledge of equipment names, their function, and the verbs used with them.\n\nThis lesson covers the most frequently examined safety equipment terms across all aviation roles.",null,null,null)
B.Sw=new A.V(B.B,"\ud83d\udee1\ufe0f Cabin Safety Equipment","**Portable oxygen unit** \u2014 portable O\u2082 bottle for crew use\n**Drop-down oxygen mask** \u2014 passenger masks, auto-deploys above 10,000 ft cabin alt\n**Life vest / Life jacket** \u2014 under-seat flotation device\n**Emergency exit** \u2014 floor-level lighting marks the path\n**Escape slide** \u2014 inflatable slide for rapid evacuation\n**Fire extinguisher** \u2014 Halon type in cockpit, water/CO\u2082 in cabin\n**ELT** \u2014 Emergency Locator Transmitter (activates on impact)",null,null,null)
B.SH=new A.V(B.B,"\ud83d\udd27 Technical Safety Equipment","**Circuit breaker (CB)** \u2014 protects electrical circuits from overload\n**Fire detector** \u2014 senses smoke/heat in engine, APU, cargo compartment\n**Fire suppression system** \u2014 discharges extinguisher agent into engine nacelle\n**Overheat detector** \u2014 warns of bleed air duct overheating\n**TCAS** \u2014 Traffic Collision Avoidance System\n**GPWS/EGPWS** \u2014 Ground Proximity Warning System",null,null,null)
B.L_=new A.aH("Oxygen masks will drop down automatically if cabin altitude exceeds 10,000 feet.","Kabin irtifas\u0131 10.000 fiti a\u015farsa oksijen maskeleri otomatik olarak d\xfc\u015fer.","drop down automatically")
B.LS=new A.aH("The fire suppression system discharged successfully into the engine nacelle.","Yang\u0131n bast\u0131rma sistemi motor kovan\u0131na ba\u015far\u0131yla de\u015farj edildi.","fire suppression system")
B.L6=new A.aH("All cabin crew must demonstrate the life vest donning procedure to passengers.","T\xfcm kabin ekibi yolculara can yele\u011fi giyinme prosed\xfcr\xfcn\xfc g\xf6stermelidir.","donning procedure")
B.Ya=s([B.L_,B.LS,B.L6],t.l)
B.Ro=new A.V(B.af,"Safety Equipment in Use",null,B.Ya,null,null)
B.R9=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'Key verbs used with safety equipment:\n\u2022 **don** = put on (life vest, oxygen mask) \u2014 formal aviation term\n\u2022 **deploy** = activate automatically (escape slide, oxygen mask)\n\u2022 **arm** = set to automatic deployment mode (door slide)\n\u2022 **discharge** = release extinguishing agent\n\u2022 **arm/disarm** doors = cabin crew action before departure/after arrival\n\nNever use "put on" in formal exam answers \u2014 use **don**.',null,null,null)
B.WA=s(["Wearing","Donning","Fitting","Applying"],t.s)
