B.Qi=new A.V(B.ae,"Weather is critical to aviation","Weather reports and navigation documents use highly standardized vocabulary. METAR, TAF, NOTAM, and ATIS use specific terms that pilots and controllers must understand instantly.\n\nThis lesson covers the most frequently tested weather and navigation terms.",null,null,null)
B.SC=new A.V(B.B,"\ud83c\udf26\ufe0f Weather Phenomena","**CAVOK** \u2014 Ceiling And Visibility OK (vis >10km, no cloud below 5000ft, no significant weather)\n**BECMG** \u2014 Becoming (gradual change within a period)\n**TEMPO** \u2014 Temporary fluctuations lasting less than 1 hour\n**CB** \u2014 Cumulonimbus (thunderstorm cloud, avoid by 20nm)\n**TSRA** \u2014 Thunderstorm with rain\n**FG** \u2014 Fog | **BR** \u2014 Mist | **RA** \u2014 Rain | **SN** \u2014 Snow",null,null,null)
B.Qd=new A.V(B.B,"\ud83e\udded Navigation Terms","**Track** \u2014 actual path over the ground\n**Heading** \u2014 direction the nose is pointing\n**Bearing** \u2014 direction from one point to another\n**QNH** \u2014 altimeter setting (sea level pressure in hPa)\n**QFE** \u2014 altimeter setting (airfield elevation, reads zero on ground)\n**ATIS** \u2014 Automatic Terminal Information Service\n**VOR/DME** \u2014 VHF Omni Range / Distance Measuring Equipment",null,null,null)
B.LQ=new A.aH("METAR LTBA 120850Z 35015KT 9999 FEW030 SCT100 18/08 Q1013 NOSIG","\u0130stanbul Atat\xfcrk, 12. g\xfcn 08:50 UTC, r\xfczgar 350\xb0/15 knot, g\xf6r\xfc\u015f >10km, 3000ft AGL az bulut, 18\xb0C, Q1013, de\u011fi\u015fiklik yok.","NOSIG")
B.L5=new A.aH("Wind shear has been reported on the approach to runway 18L.","Pist 18L yakla\u015fmas\u0131nda r\xfczgar k\u0131r\u0131lmas\u0131 bildirildi.","Wind shear")
B.LT=new A.aH("Cumulonimbus clouds must be avoided by at least 20 nautical miles.","K\xfcm\xfclonimbus bulutlar\u0131ndan en az 20 deniz mili uzak durulmal\u0131d\u0131r.","Cumulonimbus")
B.Vl=s([B.LQ,B.L5,B.LT],t.l)
B.Rd=new A.V(B.af,"METAR Example",null,B.Vl,null,null)
B.R3=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'METAR reading order (always the same):\nStation \u2192 Date/Time \u2192 Wind \u2192 Visibility \u2192 Weather \u2192 Cloud \u2192 Temperature/Dewpoint \u2192 QNH \u2192 Trend\n\n"QNH" vs "QFE":\n\u2022 **QNH** \u2192 altitude above sea level (standard, used for en-route)\n\u2022 **QFE** \u2192 altitude above aerodrome (shows 0 when on ground)\n\nMost exam questions ask about QNH.',null,null,null)
B.V5=s(["Ceiling above visibility OK","Ceiling and visibility are satisfactory with no significant weather","Clouds are visible at low altitude","Clear air visibility over 5km"],t.s)
B.a3X=new A.ab(-50,B.al,300,'In a METAR, "CAVOK" means:',B.V5,1,B.N,null,null,null)
B.Y9=s(["Temporary changes lasting less than 1 hour, occurring less than half the period","Temperature changes expected","Permanent forecast conditions","Terminal area meteorological observations"],t.s)
