B.Qj=new A.V(B.ae,"Emergency language must be learned exactly","In real emergencies and in exam questions, using the right word can make a critical difference. ICAO standards define specific terms for emergencies \u2014 these cannot be paraphrased.\n\nThis lesson focuses on the vocabulary that appears most frequently in emergency-related exam questions.",null,null,null)
B.PY=new A.V(B.B,"\ud83d\udea8 Emergency Classification","**Distress** \u2014 state of being threatened by serious and/or imminent danger, requiring immediate assistance (MAYDAY)\n\n**Urgency** \u2014 condition concerning the safety of an aircraft or other vehicle, or of some person on board or in sight, but not requiring immediate assistance (PAN-PAN)\n\n**Emergency** \u2014 broad term covering both distress and urgency situations\n\n**Incident** \u2014 occurrence other than an accident associated with flight operation\n**Accident** \u2014 occurrence resulting in death, injury, or substantial aircraft damage",null,null,null)
B.QN=new A.V(B.B,"\ud83d\udd25 Emergency Action Vocabulary","**Declare** \u2014 formally announce an emergency state\n**Divert** \u2014 change destination to an alternate airport\n**Squawk** \u2014 set transponder code\n**Dump fuel** \u2014 jettison fuel to reduce landing weight (on equipped aircraft)\n**Depressurize** \u2014 controlled or rapid loss of cabin pressure\n**Evacuate** \u2014 rapid exit of passengers and crew\n**Ditch** \u2014 emergency landing on water\n**Abort** \u2014 discontinue a takeoff roll",null,null,null)
B.Lo=new A.aH("The captain declared a MAYDAY due to rapid decompression at FL350.","Kaptan, FL350'de h\u0131zl\u0131 bas\u0131n\xe7 kayb\u0131 nedeniyle MAYDAY ilan etti.","declared a MAYDAY")
B.LI=new A.aH("The crew was forced to divert to Valencia after a hydraulic failure.","Ekip, hidrolik ar\u0131zas\u0131n\u0131n ard\u0131ndan Valencia'ya y\xf6n de\u011fi\u015ftirmek zorunda kald\u0131.","divert")
B.L4=new A.aH("Following the gear malfunction, the captain decided to abort the landing.","\u0130ni\u015f tak\u0131m\u0131 ar\u0131zas\u0131n\u0131n ard\u0131ndan kaptan ini\u015fi iptal etmeye karar verdi.","abort")
B.Yj=s([B.Lo,B.LI,B.L4],t.l)
B.Qn=new A.V(B.af,"Emergency Communication",null,B.Yj,null,null)
B.Se=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'"Incident" vs. "Accident" is a common exam question:\n\u2022 **Incident**: something happened but no one died and no major damage occurred\n\u2022 **Accident**: death, serious injury, OR substantial damage occurred\n\n"Distress" vs. "Urgency":\n\u2022 **Distress (MAYDAY)**: needs help NOW \u2014 immediate danger to life\n\u2022 **Urgency (PAN-PAN)**: serious concern, but not an immediate threat to life',null,null,null)
B.U6=s(["Incident","Accident","Emergency","Distress"],t.s)
B.a4j=new A.ab(-160,B.al,310,"An occurrence involving an aircraft that results in fatal injury or substantial damage is defined as a/an:",B.U6,1,B.N,null,null,null)
