B.S0=new A.V(B.ae,"Precise translation in aviation","Translation questions test whether you understand **both** the technical meaning of aviation phrases and their accurate Turkish equivalents.\n\nA wrong translation can indicate a misunderstanding of the procedure, which is why these questions carry significant weight in exams.",null,null,null)
B.Ss=new A.V(B.B,"\ud83d\udd11 Key Phrase Translations",'"**Cleared to land**" \u2192 Piste ini\u015fe yetkilendirildiniz\n"**Go around**" \u2192 T\u0131rmani\u015f yap\u0131n / Al\xe7al\u0131\u015f\u0131 iptal edin\n"**Hold short**" \u2192 Girmeden bekleyin\n"**Line up and wait**" \u2192 S\u0131raya girin ve bekleyin\n"**Contact [unit] on [freq]**" \u2192 [birim] ile [frekans] \xfczerinde temasa ge\xe7in\n"**Report final**" \u2192 Final pistine geldi\u011finizde bildirin\n"**Confirm**" \u2192 Teyit edin\n"**Affirm**" \u2192 Evet/Do\u011fru (Teyit ederim)',null,null,null)
B.LL=new A.aH(u.G,"THY123, al\xe7al ve u\xe7u\u015f seviyesi 150'de kal.","descend and maintain")
B.Lh=new A.aH("THY123, go around, I say again, go around.","THY123, t\u0131rman\u0131\u015f yap\u0131n, tekrar ediyorum, t\u0131rman\u0131\u015f yap\u0131n.","go around")
