B.a3O=new A.ab(-61,B.ba,427,'"Hold short of runway 18L" ifadesinin do\u011fru T\xfcrk\xe7e \xe7evirisi hangisidir?',B.X7,2,B.N,null,null,null)
B.YT=s(["Anlam\u0131yorum","Mesaj\u0131n\u0131z al\u0131nd\u0131","Anl\u0131yorum ve gere\u011fini yapaca\u011f\u0131m","Tekrar edin"],t.s)
