B.Sh=new A.V(B.B,"\ud83d\udccb ICAO Flight Plan Fields",'**Field 7** \u2014 Aircraft ID (call sign): "THY123"\n**Field 8** \u2014 Flight rules (I=IFR, V=VFR) and type (S=scheduled): "IS"\n**Field 9** \u2014 Number and type of aircraft / wake turbulence: "B738/M"\n**Field 10** \u2014 Equipment: "SDFGRY/S" (comms/nav/approach/SSR)\n**Field 15** \u2014 Route: SID + airways + waypoints + STAR\n**Field 16** \u2014 Destination + EET + alternates\n**Field 18** \u2014 Other information (PBN, DAT, SUR, etc.)',null,null,null)
B.Qk=new A.V(B.B,"\u26a0\ufe0f Wake Turbulence Categories","**J \u2014 Super** (A380, AN-124): wingspan >80m\n**H \u2014 Heavy** (B747, B777, A330): MTOW >136,000kg\n**M \u2014 Medium** (B737, A320): MTOW 7,000\u2013136,000kg\n**L \u2014 Light** (Cessna, DA-42): MTOW <7,000kg\n\nSeparation minima increase behind heavier aircraft:\n\u2022 H behind J: 6nm\n\u2022 M behind H: 5nm\n\u2022 L behind H: 6nm\n\nWake turbulence is most severe at **low speed, high angle of attack** (on approach)",null,null,null)
B.KC=new A.aH("B738/M in the flight plan means Boeing 737-800 with Medium wake turbulence category.","U\xe7u\u015f plan\u0131ndaki B738/M, Boeing 737-800 ve Orta a\u011f\u0131rl\u0131k kategorisi anlam\u0131na gelir.","/M")
B.LB=new A.aH("EET/LTAA0123 means the estimated elapsed time to the LTAA FIR boundary is 1 hour 23 minutes.","EET/LTAA0123, LTAA FIR s\u0131n\u0131r\u0131na tahmini ge\xe7i\u015f s\xfcresinin 1 saat 23 dakika oldu\u011fu anlam\u0131na gelir.","EET")
B.YD=s([B.KC,B.LB],t.l)
B.R6=new A.V(B.af,"Flight Plan Data",null,B.YD,null,null)
B.SI=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'Flight plan questions often focus on:\n\u2022 **Aircraft type / wake category** \u2014 know ICAO aircraft designators\n\u2022 **EET** (Estimated Elapsed Time) vs. **ETA** (Estimated Time of Arrival)\n\u2022 **Alternate airport** requirements \u2014 when is one required?\n\u2022 **PBN** (Performance Based Navigation) codes in Field 18\n\nCommon trick: "EOBT" = Estimated Off-Blocks Time (when pushback starts), NOT takeoff time.',null,null,null)
B.Yp=s(["High altitude aircraft","Heavy aircraft (MTOW > 136,000 kg)","Helicopter","High-speed aircraft"],t.s)
