B.Sd=new A.V(B.ae,"Abnormal checklists have fixed language patterns","Engine failure and other abnormal/emergency checklists use the most precise language in aviation. Fill-in-the-blank questions from this area test both technical knowledge and vocabulary accuracy.\n\nThe correct procedure verb is critical \u2014 using the wrong action word is never acceptable in aviation.",null,null,null)
B.Qw=new A.V(B.B,"\ud83d\udd25 Engine Failure Vocabulary","**Thrust lever** \u2014 controls engine power (throttle)\n**Fuel control lever** \u2014 starts/stops fuel to engine\n**Engine fire handle** \u2014 emergency shut-off and fire suppression control\n**HP fuel cock / Shutoff valve** \u2014 high-pressure fuel control\n**N1 / N2** \u2014 fan speed (%) / core speed (%)\n**EGT** \u2014 Exhaust Gas Temperature\n**ITT** \u2014 Interstage Turbine Temperature\n**Surge** \u2014 compressor stall; loud bang, rpm fluctuation",null,null,null)
B.R_=new A.V(B.B,"\ud83d\udccb Checklist Action Patterns",'Engine failure checklist sequence uses these exact phrases:\n\n"Engine fire, failure or severe damage \u2014 **ECAM ACTIONS**... **PERFORM**"\n"Thrust lever \u2014 **IDLE**"\n"If engine does not recover \u2014 engine **MASTER switch** \u2014 **OFF**"\n"Engine fire pushbutton \u2014 **PUSH**"\n"If fire not extinguished \u2014 **DISCHARGE** second agent"\n"Land at nearest suitable aerodrome \u2014 **CONSIDER**"\n\nKey pattern verbs: **idle, push, pull, discharge, confirm, verify, cross-check**',null,null,null)
B.Lt=new A.aH("In the event of an engine fire, the crew must pull the engine fire handle.","Motor yang\u0131n\u0131 durumunda ekip, motor yang\u0131n kolunu \xe7ekmelidir.","pull the engine fire handle")
B.LK=new A.aH("If the fire is not extinguished, discharge the second fire extinguisher agent.","Yang\u0131n s\xf6nd\xfcr\xfclemezse ikinci s\xf6nd\xfcr\xfcc\xfc maddesini de\u015farj edin.","discharge")
B.LR=new A.aH("Cross-check the affected engine number before taking any action.","Herhangi bir i\u015flem yapmadan \xf6nce etkilenen motor numaras\u0131n\u0131 \xe7apraz kontrol edin.","Cross-check")
B.Uz=s([B.Lt,B.LK,B.LR],t.l)
B.RC=new A.V(B.af,"Abnormal Checklist Language",null,B.Uz,null,null)
B.Rn=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'Checklist action verbs that are tested:\n\u2022 **Pull** fire handle (not "activate" or "turn")\n\u2022 **Discharge** extinguisher (not "release" or "fire")\n\u2022 **Cross-check** \u2014 never skip this step in exams\n\u2022 **Monitor** vs. **Check**: monitoring is continuous; checking is a single action\n\u2022 "Land at nearest suitable" \u2260 "divert immediately" \u2014 the crew must assess "suitability"',null,null,null)
B.YC=s(["pushed","pulled","turned","activated"],t.s)
B.a4g=new A.ab(-230,B.aG,780,"In the event of an engine fire, the fire handle should be \u2026\u2026\u2026\u2026 after engine shutdown.",B.YC,1,B.A,null,null,null)
B.T6=s(["turn off","confirm","cross-check","identify"],t.s)
B.a4l=new A.ab(-231,B.aG,781,"Before performing any engine shutdown action, the crew should \u2026\u2026\u2026\u2026 the affected engine.",B.T6,2,B.A,null,null,null)
B.WS=s(["activate","fire","discharge","release"],t.s)
B.a3r=new A.ab(-232,B.aG,782,"If the first fire extinguisher agent does not extinguish the fire, the crew should \u2026\u2026\u2026\u2026 the second bottle.",B.WS,2,B.A,null,null,null)
B.YV=s(["stall","surge","failure","seizure"],t.s)
B.a3j=new A.ab(-233,B.aG,783,"A compressor stall in a jet engine is also known as a compressor \u2026\u2026\u2026\u2026.",B.YV,1,B.b1,null,null,null)
