B.Qe=new A.V(B.ae,"Advanced texts use complex grammatical structures","Aviation documents, accident reports, and ICAO publications use complex sentence structures that combine multiple clauses. At the advanced level, you must handle these accurately in both comprehension and production questions.",null,null,null)
B.PZ=new A.V(B.B,"Relative Clauses",'**Defining** (no commas): identifies which one\n\u2192 "The component **that failed** was the hydraulic pump."\n\n**Non-defining** (with commas): adds extra information\n\u2192 "The hydraulic pump, **which had just been serviced**, failed."\n\n**Reduced relative clause** (participle phrase):\n\u2192 "The pilot **flying the aircraft** reported vibration." (= who was flying)\n\u2192 "The component **installed last week** is defective." (= that was installed)',null,null,null)
B.Sm=new A.V(B.B,"Participial Phrases & Inversion",'**Present participle** (active, simultaneous):\n\u2192 "**Having received** the clearance, the crew began the takeoff roll."\n\n**Past participle** (passive, completed first):\n\u2192 "**Notified by ATC**, the pilot diverted to the alternate."\n\n**Negative inversion** (formal/reports):\n\u2192 "**Under no circumstances should** the aircraft depart without a clearance."\n\u2192 "**Not until the checks were completed** did the captain approve departure."',null,null,null)
B.LW=new A.aH("The maintenance technician, having completed all required inspections, signed the aircraft log.","Bak\u0131m teknisyeni, gerekli t\xfcm denetimleri tamamlad\u0131ktan sonra u\xe7ak k\xfct\xfc\u011f\xfcn\xfc imzalad\u0131.","having completed")
B.LU=new A.aH("Under no circumstances should flight crew members operate the aircraft beyond approved limits.","U\xe7u\u015f ekibi \xfcyeleri hi\xe7bir ko\u015fulda u\xe7a\u011f\u0131 onaylanan limitler d\u0131\u015f\u0131nda kullanmamal\u0131d\u0131r.","Under no circumstances should")
B.SW=s([B.LW,B.LU],t.l)
B.Rf=new A.V(B.af,"Complex Structure Examples",null,B.SW,null,null)
B.Sr=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'Inversion signals in exam questions:\n\u2022 "Under no circumstances\u2026" \u2192 should/must come before subject\n\u2022 "Not until\u2026" \u2192 did/could comes before subject in main clause\n\u2022 "Only after\u2026" \u2192 inversion in main clause\n\nParticiple phrases \u2014 check the subject:\n\u2022 "**Having landed**, the aircraft was directed to the gate." \u2713 (aircraft landed)\n\u2022 "**Having landed**, the gate was assigned." \u2717 (gate didn\'t land \u2014 dangling participle)',null,null,null)
B.Vw=s(["that installed","installed","which installed","installing"],t.s)
B.a4c=new A.ab(-250,B.ak,230,"The hydraulic pump \u2026\u2026\u2026\u2026 last week has already failed.",B.Vw,1,B.b1,null,null,null)
B.XW=s(["crew members should","should crew members","do crew members","crew members must"],t.s)
B.a4a=new A.ab(-251,B.ak,231,"Under no circumstances \u2026\u2026\u2026\u2026 crew members disable the fire detection system.",B.XW,1,B.b1,null,null,null)
B.TN=s(["Having completed","Completed","After completing to","Being completed"],t.s)
