B.PJ=new A.ch("reading_5","SID/STAR Procedures","reading","\ud83d\uddfa\ufe0f",B.UP)
B.RB=new A.V(B.ae,"Accident reports are complex texts","Aviation accident investigation reports (such as those produced by ICAO Annex 13 standards) are among the most complex texts tested in aviation English exams.\n\nThey contain technical terminology, passive constructions, reported speech, and conditional reasoning \u2014 all combined in a single document.",null,null,null)
B.Si=new A.V(B.B,"\ud83d\udccb Report Structure","A standard accident report contains:\n1. **Synopsis** \u2014 brief summary of the accident\n2. **Factual information** \u2014 aircraft, crew, weather, airport data\n3. **Analysis** \u2014 what happened and why (cause chain)\n4. **Findings** \u2014 established facts\n5. **Cause** \u2014 probable cause(s)\n6. **Safety recommendations** \u2014 what should change\n\nExam questions usually target **Factual Information** and **Analysis** sections.",null,null,null)
B.Sl=new A.V(B.B,"\ud83d\udd0d Critical Reading Skills","For accident report passages:\n\u2022 **Sequence words**: prior to, during, following, subsequently, as a result\n\u2022 **Causal language**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Finding vs. Recommendation**: findings are facts; recommendations are suggestions\n\u2022 **Contributing factor** \u2260 **Probable cause**: contributing factors worsen the situation; probable cause is the primary reason",null,null,null)
B.KQ=new A.aH("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.Ll=new A.aH("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.Up=s([B.KQ,B.Ll],t.l)
B.QB=new A.V(B.af,"Report Language Examples",null,B.Up,null,null)
B.R1=new A.V(B.ag,"\u2708\ufe0f Advanced Reading Strategy","The 3-read method for complex passages:\n1. **First read**: skim for topic and structure (30 seconds)\n2. **Read question**: understand exactly what is asked\n3. **Second read**: focus on the relevant paragraph only\n\nNever answer from memory \u2014 always verify in the text. Advanced questions often have **plausible but incorrect** distractors that use words from the passage in the wrong context.",null,null,null)
B.UD=s(["To start the engine for the first time","To test the fuel system","To increase engine speed","To test the electrical system"],t.s)
B.a4O=new A.ab(-100,B.az,606,"What is the purpose of wet motoring the engine?",B.UD,1,B.N,null,null,null)
B.TZ=s(["Both are turned ON","One is ON and one is OFF","Both are turned OFF","The position does not matter"],t.s)
B.a4f=new A.ab(-101,B.az,607,"During wet motoring, what is the position of the ignition systems?",B.TZ,2,B.N,null,null,null)
B.VJ=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
B.a3S=new A.ab(-102,B.az,608,"What is monitored during the wet motoring test?",B.VJ,2,B.A,null,null,null)
B.VK=s([B.a4O,B.a4f,B.a3S],t.C)
B.Qm=new A.V(B.a7,"Practice Questions",'"Wet motoring the engine is necessary to test the fuel system. When an engine is wet motored, the two ignition systems are turned OFF and the starter is engaged to turn the HP rotor to 15%-20% N2. At N2 = 15%, the HP fuel shutoff valve control lever is moved to ON and the engine exhaust nozzle is carefully monitored for any sign of fuel."',null,null,B.VK)
B.Z7=s([B.RB,B.Si,B.Sl,B.QB,B.R1,B.Qm],t.q)
B.Pg=new A.ch("reading_2","Accident Report Analysis","reading","\ud83d\udcd1",B.Z7)
B.Rs=new A.V(B.ae,"Low visibility operations demand precise language","CAT II and CAT III approaches are conducted in very low visibility using autoland systems. The phraseology, alerts, and callouts in these procedures are among the most precisely defined in aviation English.\n\nSentence completion questions in this area require exact knowledge of procedure terminology.",null,null,null)
B.QG=new A.V(B.B,"\ud83c\udf2b\ufe0f ILS Categories","**CAT I** \u2014 DH \u2265200ft, RVR \u2265550m (standard ILS)\n**CAT II** \u2014 DH 100\u2013200ft, RVR \u2265300m (needs specific aircraft/crew cert)\n**CAT IIIA** \u2014 DH <100ft OR no DH, RVR \u2265200m\n**CAT IIIB** \u2014 DH <50ft OR no DH, RVR 50\u2013200m\n**CAT IIIC** \u2014 No DH, No RVR limit (still not in service)\n\n**LVP** \u2014 Low Visibility Procedures (activated by airport when RVR <600m)\n**LVT** \u2014 Low Visibility Takeoff",null,null,null)
B.PU=new A.V(B.B,"\ud83d\udce2 CAT III Callouts",'Standard CAT III approach callouts (in order):\n1. "**Localizer alive**" \u2014 ILS localizer captured\n2. "**Glide slope alive**" \u2014 vertical guidance captured\n3. "**Land 3**" \u2014 autoland mode confirmed (A320 family)\n4. "**1,000 feet**" \u2014 standard check altitude\n5. "**500 feet**" \u2014 stability check\n6. "**100 feet**" \u2014 visual or go-around decision\n7. "**50, 40, 30, 20, 10**" \u2014 radio altimeter callouts\n8. "**Touchdown**" \u2192 "**Decelerate**" \u2192 "**Vacate**"',null,null,null)
B.KZ=new A.aH("During LVP, ground movement must be strictly controlled to prevent runway incursion.","LVP s\u0131ras\u0131nda pist ihlalini \xf6nlemek i\xe7in yer hareketi kesinlikle kontrol edilmelidir.","LVP")
B.KJ=new A.aH("At Decision Height, if the required visual reference is not established, a go-around must be executed.","Karar \u0130rtifas\u0131nda, gerekli g\xf6rsel referans sa\u011flanamazsa t\u0131rman\u0131\u015f prosed\xfcr\xfc uygulanmal\u0131d\u0131r.","Decision Height")
B.V8=s([B.KZ,B.KJ],t.l)
B.QQ=new A.V(B.af,"CAT III Completion Examples",null,B.V8,null,null)
B.RJ=new A.V(B.ag,"\u2708\ufe0f Exam Tip",'CAT II/III key distinctions for exams:\n\u2022 **DH** = Decision Height (radio altimeter based, CAT II/III)\n\u2022 **DA** = Decision Altitude (barometric, CAT I)\n\u2022 **RVR** = Runway Visual Range (measured by transmissometers)\n\u2022 A CAT IIIB approach may be conducted with **no Decision Height** if auto-rollout/auto-brake available\n\u2022 LVP does NOT cancel low-visibility departures automatically \u2014 there are separate LVT minima\n\u2022 "Required visual reference" for CAT III is **less** than for CAT I (may be just runway edge lights)',null,null,null)
B.We=s(["Minimum Descent","Decision Height","Decision Altitude","Obstacle Clearance"],t.s)
B.a31=new A.ab(-280,B.bZ,980,"A CAT III approach uses \u2026\u2026\u2026\u2026 altitude as the reference point for the go-around decision.",B.We,1,B.A,null,null,null)
B.VI=s(["800 meters","1,000 meters","600 meters","400 meters"],t.s)
B.a3V=new A.ab(-281,B.bZ,981,"LVP (Low Visibility Procedures) are normally activated when RVR drops below \u2026\u2026\u2026\u2026.",B.VI,2,B.b1,null,null,null)
B.Vq=s(["550 meters","300 meters","200 meters","100 meters"],t.s)
B.a48=new A.ab(-282,B.bZ,982,"For a CAT IIIA approach, the minimum RVR is \u2026\u2026\u2026\u2026.",B.Vq,2,B.b1,null,null,null)
B.XA=s(["Third approach attempt","Autoland is armed and all three redundant systems are active","Landing gear is down and locked","CAT III clearance received"],t.s)
B.a3u=new A.ab(-283,B.bZ,983,'The autoland system callout "LAND 3" on an Airbus A320 indicates:',B.XA,1,B.b1,null,null,null)
