B.PA=new A.ch("completion_3","CAT III Approach Procedures","sentence_completion","\ud83c\udf2b\ufe0f",B.Uo)
B.Sb=new A.V(B.ae,"Advanced clearances combine multiple elements","At the advanced level, ATC clearances contain multiple simultaneous instructions \u2014 altitude, heading, speed, frequency, and transponder \u2014 all in a single transmission. Parsing and completing these accurately is a high-level skill tested in expert-level exams.",null,null,null)
B.SF=new A.V(B.B,"\ud83d\uddfc Oceanic & Complex Clearance Elements",'**Oceanic clearance:** "THY1 is cleared to New York JFK via track Bravo, flight level 360, Mach 0.84, squawk 2341"\n\n**Complex enroute:** "THY456, cross TURPO at or above FL280, then direct EMEVI, reduce to Mach 0.80"\n\n**Conditional clearance:** "Behind the departing B777, line up runway 34L and wait"\n\u2014 Always read back: **type of aircraft + condition + instruction**\n\n**SELCAL** \u2014 Selective Calling system for oceanic comms\n**HF** \u2014 High Frequency radio (used in oceanic areas beyond VHF range)',null,null,null)
B.RI=new A.V(B.B,"\ud83d\udd04 Holding Clearance Language",'"THY123, hold at TURPO as published, expect approach in 20 minutes"\n"\u2026\u2026\u2026\u2026 to the right on the 150 radial, 1-minute legs"\n\n**Key holding terms:**\n\u2022 **Inbound course** \u2014 heading toward the fix during holding\n\u2022 **Outbound leg** \u2014 time/distance spent flying away from fix\n\u2022 **Expect further clearance (EFC)** \u2014 time pilot can expect to leave the hold\n\u2022 **Published hold** \u2014 charted holding pattern; use standard values\n\u2022 "**Left / right turns**" \u2014 direction of turns in the hold',null,null,null)
B.L1=new A.aH("THY123, cross TURPO at or above FL260, then direct EMEVI, Mach 0.82.","THY123, TURPO'yu FL260 veya \xfczerinde ge\xe7in, ard\u0131ndan EMEVI'ye direkt, Mach 0.82.","cross TURPO at or above")
B.Lj=new A.aH("Behind the departing A330, line up runway 18L and wait.","Kalkan A330'un arkas\u0131nda, pist 18L'ye s\u0131raya girin ve bekleyin.","Behind the departing")
B.LM=new A.aH("Hold at VESAS on the 270 radial, right turns, 1-minute legs, expect approach at 1430.","VESAS'ta 270 radyal \xfczerinde, sa\u011f turlar, 1 dakikal\u0131k bacaklar, saat 14:30'da yakla\u015fma bekleniyor.","Hold at")
B.Wa=s([B.L1,B.Lj,B.LM],t.l)
B.Sz=new A.V(B.af,"Advanced Clearance Examples",null,B.Wa,null,null)
B.Sn=new A.V(B.ag,"\u2708\ufe0f Advanced Exam Tips",'Conditional clearances \u2014 always identify:\n1. **Condition** \u2014 which aircraft / when\n2. **Instruction** \u2014 what to do\n3. **Readback** must include the condition: "Behind the B777 on final, cleared to land, THY456"\n\nOceanic clearances always include: track letter + FL + Mach number + squawk\n\nEFC (Expect Further Clearance) is NOT a clearance to leave the hold \u2014 the pilot must wait for the actual clearance.',null,null,null)
B.Uv=s(["After","Following","Behind","When"],t.s)
B.a3p=new A.ab(-290,B.aG,790,'"\u2026\u2026\u2026\u2026 the A330 on final, line up runway 34L and wait." \u2014 The missing word is:',B.Uv,2,B.A,null,null,null)
B.Vu=s(["Knots","IAS","Mach","TAS"],t.s)
B.a3m=new A.ab(-291,B.aG,791,"An oceanic clearance always includes the assigned \u2026\u2026\u2026\u2026 number as the track speed reference.",B.Vu,2,B.b1,null,null,null)
B.Zk=s(["left or right","standard","right","left"],t.s)
B.a3M=new A.ab(-292,B.aG,792,'"Hold at TURPO, \u2026\u2026\u2026\u2026 turns, 1-minute legs, expect clearance at 1520."',B.Zk,2,B.A,null,null,null)
B.W3=s(["at or above","at minimum","maintaining","no lower than"],t.s)
B.a4q=new A.ab(-293,B.aG,793,'"THY456, cross EMEVI \u2026\u2026\u2026\u2026 FL240." \u2014 The missing phrase is:',B.W3,0,B.A,null,null,null)
