B.X9=s([B.Sb,B.SF,B.RI,B.Sz,B.Sn,B.PW],t.q)
B.Pp=new A.ch("fill_5","Advanced ATC Clearances","fill_blanks","\ud83d\uddfc",B.X9)
B.Qp=new A.V(B.ae,"Accident reports use precise legal and technical language","ICAO Annex 13 accident investigation reports are among the most linguistically demanding documents in aviation. They combine legal precision, passive constructions, technical accuracy, and causal analysis in a single text.\n\nTranslation questions from these reports require understanding both the technical meaning and the legal implications of each phrase.",null,null,null)
B.RO=new A.V(B.B,"\u26a0\ufe0f Causal Language",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.Ru=new A.V(B.B,"\ud83d\udccb Investigation Findings Language",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.LX=new A.aH("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.Lx=new A.aH("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
B.LV=new A.aH("The investigation attributed the loss of situational awareness to crew fatigue and inadequate CRM.","Soru\u015fturma, durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131n\u0131 m\xfcrettebat yorgunlu\u011funa ve yetersiz EKY'ye ba\u011flad\u0131.","attributed to")
B.Ze=s([B.LX,B.Lx,B.LV],t.l)
B.QT=new A.V(B.af,"Report Passage Examples",null,B.Ze,null,null)
B.S1=new A.V(B.ag,"\u2708\ufe0f Translation Exam Strategy",'For accident report translation questions:\n\u2022 "**Probable cause**" \u2260 "possible cause" \u2014 it is the MOST LIKELY established cause\n\u2022 "**Contributing factor**" \u2260 "main reason" \u2014 it is a secondary, exacerbating condition\n\u2022 "**Crew failed to**" = they did not do something required \u2014 not necessarily negligence\n\u2022 "**It could not be determined**" = insufficient evidence \u2014 do NOT translate as "it is unknown"\n\u2022 "**Contrary to SOP**" = a procedure violation \u2014 always serious in reports',null,null,null)
B.Yx=s(["The accident was caused by an out-of-control aircraft hitting terrain","The aircraft was in controlled flight when it struck terrain","The crew controlled the aircraft into terrain intentionally","The terrain was controlled by ATC when the accident occurred"],t.s)
B.a4p=new A.ab(-300,B.ba,460,'"The accident was attributed to controlled flight into terrain." This means:',B.Yx,1,B.A,null,null,null)
B.Yk=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.a49=new A.ab(-301,B.ba,461,'"Contrary to standard operating procedures" means:',B.Yk,1,B.A,null,null,null)
B.Yd=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.a44=new A.ab(-302,B.ba,462,'"A contributing factor was the inadequate crew rest period." This means:',B.Yd,1,B.A,null,null,null)
B.UR=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.a3P=new A.ab(-303,B.ba,463,'"It could not be determined whether\u2026" in a report means:',B.UR,1,B.b1,null,null,null)
B.Y3=s([B.a4p,B.a49,B.a44,B.a3P],t.C)
B.S9=new A.V(B.a7,"Practice Questions",null,null,null,B.Y3)
B.UT=s([B.Qp,B.RO,B.Ru,B.QT,B.S1,B.S9],t.q)
B.PF=new A.ch("translation_4","Accident Investigation Reports","translation","\ud83d\udcf0",B.UT)
B.RH=new A.V(B.ae,"ADs are mandatory safety compliance documents","An Airworthiness Directive (AD) is a legally binding document issued by a civil aviation authority requiring specific action to correct an unsafe condition in an aircraft type. Non-compliance is illegal and grounds for operating certificate suspension.\n\nAD language is the most precise regulatory language in aviation \u2014 every word has legal weight.",null,null,null)
B.Rk=new A.V(B.B,"\ud83d\udcdc AD Structure",'A typical AD contains:\n1. **Applicability** \u2014 which aircraft/engines/parts are affected\n2. **Unsafe condition** \u2014 the hazard being addressed\n3. **Required action** \u2014 what must be done\n4. **Compliance time** \u2014 when it must be done (e.g., "within 50 flight hours")\n5. **Method** \u2014 how to comply (service bulletin, specific procedure)\n6. **Alternative Method of Compliance (AMOC)** \u2014 approved alternative\n7. **Costs** \u2014 estimated compliance cost',null,null,null)
B.PO=new A.V(B.B,"\u26a0\ufe0f Compliance Time Language",'**"Within 50 flight hours after the effective date"** \u2014 must be done before 50 more hours\n**"At the next scheduled maintenance"** \u2014 at next A/B/C check\n**"Before further flight"** \u2014 aircraft must not fly until complied with\n**"At first opportunity"** \u2014 as soon as practical (not as urgent as "before further flight")\n**"Repetitive inspection every 200 FH"** \u2014 not a one-time action; must be repeated\n**"Terminating action"** \u2014 permanently satisfies the AD (no more repetitive checks needed)',null,null,null)
B.KE=new A.aH("This AD requires repetitive inspections of the fuselage skin every 500 flight cycles.","Bu AD, her 500 u\xe7u\u015f \xe7evriminde g\xf6vde kaplamas\u0131n\u0131n tekrarl\u0131 denetimlerini gerektirmektedir.","repetitive inspections")
B.Lu=new A.aH("The applicability of this AD extends to all Boeing 737-800 aircraft with serial numbers 35201 through 41234.","Bu AD'nin uygulanabilirli\u011fi, 35201 ile 41234 aras\u0131ndaki seri numaralar\u0131na sahip t\xfcm Boeing 737-800 u\xe7aklar\u0131n\u0131 kapsamaktad\u0131r.","applicability")
B.KG=new A.aH("Compliance is required before further flight after the effective date.","Y\xfcr\xfcrl\xfck tarihinden sonra daha fazla u\xe7u\u015ftan \xf6nce uyum zorunludur.","before further flight")
